import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { NameResolver } from '../processors/NameResolver';
import { extractTransactionsWithModel } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V65 - EXECUTIVE MODE)
 * -------------------------------------------------------
 * Executa o contrato aprendido no Laboratório com rigor absoluto.
 * Modo puramente executivo: desativa interpretação visual e heurísticas globais.
 */
export const ContractExecutor = {
    async apply(model: FileModel, adaptedInput: any, _globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");

        // 🛡️ BLINDAGEM EXECUTIVA: No lançamento, ignoramos o Base64 (Visual) para evitar reinterpretação.
        // Forçamos o uso apenas do Texto Bruto extraído do PDF/Arquivo para garantir fidelidade ao DNA textual.
        const rawBase64 = undefined; 

        if (!rawText.trim()) return [];

        const { mapping } = model;

        /**
         * 🧱 MODO BLOCO (DETERMINÍSTICO VIA TEXTO)
         * O contrato de bloco é aplicado sobre o Texto Bruto.
         */
        if (mapping.extractionMode === 'BLOCK') {
            const trainingContext = mapping.blockContract;
            if (!trainingContext) {
                console.warn("[ContractExecutor] Alerta: Modelo BLOCK sem blockContract salvo.");
                return [];
            }

            try {
                // Execução estritamente textual para garantir fidelidade ao texto do documento.
                const aiResult = await extractTransactionsWithModel(rawText, trainingContext, rawBase64);
                const rows = Array.isArray(aiResult) ? aiResult : (aiResult?.rows || []);

                return rows.map((tx: any, idx: number) => ({
                    id: `viva-block-${model.id}-${idx}-${Date.now()}`,
                    date: tx.date,
                    description: String(tx.description || "").toUpperCase().trim(), 
                    rawDescription: tx.description, 
                    amount: tx.amount,
                    originalAmount: String(tx.amount),
                    cleanedDescription: tx.description,
                    contributionType: tx.tipo || 'AUTO',
                    paymentMethod: tx.forma || 'OUTROS',
                    bank_id: model.id
                }));
            } catch (e) { 
                console.error("[ContractExecutor] Falha na extração soberana:", e);
                return []; 
            }
        }

        /**
         * 🚀 MODO COLUNAS (DETERMINÍSTICO - EXCEL/CSV)
         * Réplica exata da simulação, removendo heurísticas de limpeza global.
         */
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
        const results: Transaction[] = [];
        const currentYear = new Date().getFullYear();

        // SOBERANIA DO MODELO: Usa apenas o que o usuário treinou no Laboratório.
        const modelKeywords = mapping.ignoredKeywords || [];

        lines.forEach((line, idx) => {
            if (idx < (mapping.skipRowsStart || 0)) return;

            const delimiter = line.includes(';') ? ';' : (line.includes('\t') ? '\t' : ',');
            const cells = line.split(delimiter).map(c => c.trim());

            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";
            const rawForm = (mapping.paymentMethodColumnIndex !== undefined && mapping.paymentMethodColumnIndex >= 0) 
                ? cells[mapping.paymentMethodColumnIndex] 
                : "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, currentYear);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                // LIMPEZA RESTRITA: Apenas palavras do modelo. Zero heurística global no lançamento.
                // Isso garante que "PIX RECEBIDO" não suma se o usuário não pediu isso no modelo específico.
                const learnedDescription = NameResolver.clean(rawDesc, modelKeywords, []);

                results.push({
                    id: `viva-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: learnedDescription, 
                    rawDescription: rawDesc, 
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: learnedDescription,
                    contributionType: numAmount >= 0 ? 'ENTRADA' : 'SAÍDA',
                    paymentMethod: rawForm || 'OUTROS',
                    bank_id: model.id
                });
            }
        });

        return results;
    }
};

import { GoogleGenAI, Type } from "@google/genai";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

let isAIBusy = false;

/**
 * 🛡️ PARSER RESILIENTE (V4 - ULTRA RECOVERY)
 * Recupera o máximo de dados de um JSON truncado pela IA ou rede.
 */
const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();

    // Limpeza de Markdown
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    const tryParse = (str: string) => {
        try {
            const parsed = JSON.parse(str);
            if (parsed.rows) return parsed.rows;
            if (parsed.transactions) return parsed.transactions;
            return Array.isArray(parsed) ? parsed : null;
        } catch { return null; }
    };

    // 1. Tentativa Direta (Standard)
    let result = tryParse(sanitized);
    if (result) return result;

    // 2. Recuperação de Truncamento (Brute-force closing)
    let lastBrace = sanitized.lastIndexOf('}');

    const possibleClosures = [
        '',           // Apenas o que restou
        ']',          // Se cortou num array
        ']}',         // Se cortou num objeto com array 'rows'
        '"}]}',       // Se cortou dentro de uma string de um objeto num array
        '"}',         // Se cortou dentro de uma string de um objeto
    ];

    while (lastBrace > 0) {
        const base = sanitized.substring(0, lastBrace + 1);
        for (const closure of possibleClosures) {
            const candidate = base + closure;
            result = tryParse(candidate);
            if (result) {
                console.warn("[GeminiService] JSON recuperado via truncamento na posição:", lastBrace);
                return result;
            }
        }
        lastBrace = sanitized.lastIndexOf('}', lastBrace - 1);
    }

    console.error("[GeminiService] Falha total ao recuperar JSON corrompido.");
    return fallback;
};

/**
 * 🎯 MOTOR DE EXTRAÇÃO SOBERANO (MODO DETERMINÍSTICO / EXECUTIVO)
 * No modo de contrato, o Gemini atua apenas como um parser técnico de baixo nível.
 */
export const extractTransactionsWithModel = async (
    rawText: string, 
    modelContext?: string, 
    base64Data?: string,
    limit?: number
): Promise<any> => {
    if (isAIBusy) return { rows: [] };
    isAIBusy = true;

    try {
        const ai = getAIClient();
        const isContractExecution = modelContext?.includes("CONTRATO RIGOROSO");

        const isPreview = !!limit;
        const limitInstruction = isPreview 
            ? `RESTRICAO: Processe apenas os primeiros ${limit} registros.`
            : `PROCESSAMENTO TOTAL: Extraia todos os dados do documento.`;

        // 🛡️ BLINDAGEM DE PROMPT: Modo Executivo remove qualquer subjetividade ou "inteligência auditora".
        const instruction = isContractExecution 
            ? `VOCÊ É UM MOTOR DE PARSE DETERMINÍSTICO DE BAIXO NÍVEL. 

               --- CONTRATO DE MAPEAMENTO (ÚNICA VERDADE ABSOLUTA) ---
               ${modelContext}

               --- REGRAS TÉCNICAS DE EXECUÇÃO ---
               1. Extraia os dados seguindo a estrutura exata e as relações físicas do CONTRATO acima. 
               2. PROIBIDO: Adicionar, limpar, resumir, corrigir ou interpretar descrições.
               3. PROIBIDO: Alterar sinais de valores (+/-) ou formatos de datas fora do mapeamento literal.
               4. Extraia cada linha como um objeto individual sem agrupar.
               5. ${limitInstruction}

               RETORNO OBRIGATÓRIO: JSON rigoroso { "rows": [ { "date", "description", "amount", "forma", "tipo" } ] }`
            : `VOCÊ É UM AUDITOR FINANCEIRO. Extraia as transações seguindo este contexto: ${modelContext}. 
               Sinal de Débito = Negativo. 
               RETORNO: JSON { "rows": [] }`;

        const parts: any[] = [];
        if (base64Data) {
            parts.push({ inlineData: { data: base64Data, mimeType: 'application/pdf' } });
        } else {
            parts.push({ text: `CONTEÚDO BRUTO DO DOCUMENTO:\n${isPreview ? rawText.substring(0, 15000) : rawText}` });
        }
        parts.push({ text: instruction });

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', 
            contents: { parts },
            config: {
                temperature: 0, // Zero criatividade/variabilidade
                maxOutputTokens: 64000, 
                // 🛑 DESATIVAÇÃO DE REASONING EM MODO EXECUTIVO
                // Forçamos o modelo a não "pensar" ou "raciocinar", apenas realizar o mapeamento direto de tokens.
                thinkingConfig: { thinkingBudget: isContractExecution ? 0 : 32000 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER },
                                    forma: { type: Type.STRING },
                                    tipo: { type: Type.STRING }
                                },
                                required: ["date", "description", "amount", "forma", "tipo"]
                            }
                        }
                    },
                    required: ["rows"]
                }
            }
        });
        return safeJsonParse(response.text);
    } finally {
        isAIBusy = false;
    }
};

export const getRawStructuralDump = async (base64Data: string): Promise<any[]> => {
    if (isAIBusy) return [];
    isAIBusy = true;
    try {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { data: base64Data, mimeType: 'application/pdf' } },
                    { text: "Identifique blocos de transações. Retorne array JSON 'rawLines'." }
                ]
            },
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rawLines: { type: Type.ARRAY, items: { type: Type.STRING } }
                    }
                }
            }
        });
        const result = JSON.parse(response.text || '{"rawLines": []}');
        return result.rawLines || [];
    } finally {
        isAIBusy = false;
    }
};

export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    if (isAIBusy) return null;
    isAIBusy = true;
    try {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Analise o padrão de colunas deste texto: ${sampleText.substring(0, 3000)}`,
            config: { 
                temperature: 0, 
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        extractionMode: { type: Type.STRING },
                        dateColumnIndex: { type: Type.INTEGER },
                        descriptionColumnIndex: { type: Type.INTEGER },
                        amountColumnIndex: { type: Type.INTEGER },
                        skipRowsStart: { type: Type.INTEGER }
                    }
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } finally {
        isAIBusy = false;
    }
};

