export const StrategyEngine = {
    process: async (
        filename: string, 
        content: any, 
        models: FileModel[] = [], 
        globalKeywords: string[] = [], 
        overrideModel?: FileModel
    ): Promise<StrategyResult> => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const source = content?.__source || 'unknown';

        // Se um modelo foi forçado (ex: via Laboratório), usa ele imediatamente
        if (overrideModel) {
            const txs = await DatabaseModelStrategy.parse(content, overrideModel, globalKeywords);
            return { transactions: txs, strategyName: `Treino: ${overrideModel.name}` };
        }

        // Gera DNA para busca no banco de modelos
        const fileFp = Fingerprinter.generate(rawText);

        // BUSCA SOBERANA: Match por Hash ou Padrão Estrutural
        const targetModel = models.find(m => {
            if (!m.is_active) return false;
            // Match exato de DNA
            if (m.fingerprint.headerHash === fileFp?.headerHash) return true;
            // Fallback genômico (mesma estrutura de colunas/tipos)
            return (m.fingerprint.structuralPattern && 
                    m.fingerprint.structuralPattern !== 'UNKNOWN' &&
                    m.fingerprint.structuralPattern === fileFp?.structuralPattern);
        });

        if (targetModel) {
            const txs = await DatabaseModelStrategy.parse(content, targetModel, globalKeywords);
            return { 
                transactions: txs, 
                strategyName: `Contrato: ${targetModel.name}`,
                fingerprint: fileFp 
            };
        }

        // Se não há modelo e a fonte é um arquivo real, bloqueia e requisita treinamento
        if (source === 'file' || source === 'unknown') {
            console.warn(`[StrategyEngine] ⚠️ Bloqueio: DNA não reconhecido (${fileFp?.headerHash}).`);
            return { 
                status: 'MODEL_REQUIRED',
                fileName: filename,
                fingerprint: fileFp,
                preview: rawText.substring(0, 500),
                transactions: [], 
                strategyName: 'Requisitar Modelo'
            };
        }

        return { transactions: [], strategyName: 'Inconclusivo' };
    }
};

import { supabase } from './supabaseClient';
import { FileModel } from '../types';
import { Logger } from './monitoringService';
import { get, set, del } from 'idb-keyval';

const PERSISTENT_STORAGE_KEY = 'identificapix-models-storage-v12';

/**
 * 🧬 REIDRATADOR SOBERANO
 * Garante que independentemente de como o Supabase ou o Cache retornem o dado,
 * o objeto FileModel terá seus campos JSON (mapping, fingerprint, rules) como Objetos.
 */
const normalizeModel = (row: any): FileModel => {
    if (!row) return row;

    // Converte strings JSON em objetos reais se necessário
    const fingerprint = typeof row.fingerprint === 'string' ? JSON.parse(row.fingerprint) : row.fingerprint;
    const mapping = typeof row.mapping === 'string' ? JSON.parse(row.mapping) : row.mapping;
    const parsingRules = row.parsing_rules 
        ? (typeof row.parsing_rules === 'string' ? JSON.parse(row.parsing_rules) : row.parsing_rules) 
        : { ignoredKeywords: [], rowFilters: [] };

    return {
        ...row,
        id: row.id,
        name: row.name,
        user_id: row.user_id,
        version: row.version || 1,
        lineage_id: row.lineage_id || row.id,
        is_active: row.is_active,
        status: row.status || 'approved',
        fingerprint,
        mapping,
        parsingRules,
        snippet: row.snippet,
        createdAt: row.created_at || new Date().toISOString(),
        lastUsedAt: row.last_used_at
    };
};

export const modelService = {
    getUserModels: async (userId: string): Promise<FileModel[]> => {
        try {
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .or(`is_active.eq.true,user_id.eq.${userId}`);

            if (error) throw error;

            const remoteModels = data ? data.map(normalizeModel) : [];
            await set(PERSISTENT_STORAGE_KEY, remoteModels);
            return remoteModels;

        } catch (e) {
            console.warn("[ModelService] Usando cache local...", e);
            const cached = await get(PERSISTENT_STORAGE_KEY);
            return Array.isArray(cached) ? cached.map(normalizeModel) : [];
        }
    },

    saveModel: async (model: Omit<FileModel, 'id' | 'createdAt'>): Promise<FileModel | null> => {
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error("Sessão expirada.");

            if (model.lineage_id) {
                await supabase.from('file_models')
                    .update({ is_active: false })
                    .eq('lineage_id', model.lineage_id);
            }

            const { data, error } = await supabase
                .from('file_models')
                .insert([{
                    name: model.name,
                    user_id: session.user.id,
                    version: model.version || 1,
                    lineage_id: model.lineage_id || `mod-${Date.now()}`,
                    is_active: true,
                    status: model.status || 'approved',
                    fingerprint: model.fingerprint,
                    mapping: model.mapping,
                    parsing_rules: model.parsingRules,
                    snippet: model.snippet
                }])
                .select('*')
                .single();

            if (error) throw error;
            await del(PERSISTENT_STORAGE_KEY);
            return normalizeModel(data); // 🧱 Hidratação imediata pós-save
        } catch (error) {
            Logger.error("Erro ao salvar modelo", error);
            throw error;
        }
    },

    updateModel: async (id: string, updates: Partial<FileModel>): Promise<FileModel | null> => {
        try {
            const { data, error } = await supabase
                .from('file_models')
                .update({
                    name: updates.name,
                    status: updates.status,
                    fingerprint: updates.fingerprint,
                    mapping: updates.mapping,
                    parsing_rules: updates.parsingRules,
                    snippet: updates.snippet,
                    last_used_at: new Date().toISOString()
                })
                .eq('id', id)
                .select('*')
                .single();

            if (error) throw error;
            await del(PERSISTENT_STORAGE_KEY);
            return normalizeModel(data); // 🧱 Hidratação imediata pós-update
        } catch (error) {
            Logger.error("Erro ao atualizar modelo", error);
            throw error;
        }
    },

    deleteModel: async (id: string) => {
        const { error } = await supabase.from('file_models').delete().eq('id', id);
        if (!error) {
            await del(PERSISTENT_STORAGE_KEY);
            return true;
        }
        return false;
    },

    getAllModelsAdmin: async (): Promise<FileModel[]> => {
        const { data, error } = await supabase.from('file_models').select('*').order('created_at', { ascending: false });
        if (error) return [];
        return (data as any[]).map(normalizeModel); // 🧱 Hidratação para Admin
    },

    updateModelName: async (id: string, name: string) => {
        const { error } = await supabase.from('file_models').update({ name }).eq('id', id);
        if (!error) {
            await del(PERSISTENT_STORAGE_KEY);
            return true;
        }
        return false;
    }
};

